


 import jsPDF from "jspdf";
(function (jsPDFAPI) {
var font = "";
var callAddFont = function () {
this.addFileToVFS("KhmerOS_sys-normal.ttf", font);
this.addFont("KhmerOS_sys-normal.ttf", "KhmerOS_sys", "normal");
};
jsPDFAPI.events.push(['addFonts', callAddFont])
 })(jsPDF.API);

 export {}; // make it a valid ES module